import '../../../core/api/api_client.dart';
class WalletRepository { WalletRepository(this._api); final ApiClient _api; Future<int> balance() async => (await _api.get('/wallet/balance'))['balance'] as int; Future<List<Map<String, dynamic>>> transactions() async => ((await _api.get('/wallet/transactions'))['items'] as List).map((e) => Map<String, dynamic>.from(e as Map)).toList(); Future<void> deposit(int amount, String reference) => _api.post('/wallet/deposits', data: {'amount': amount, 'reference': reference}).then((_) {}); Future<void> withdrawal(int amount, String reference) => _api.post('/wallet/withdrawals', data: {'amount': amount, 'reference': reference}).then((_) {}); }
